        self.retry_after = retry_after


@app.exception_handler(RateLimitExceeded)
async def rate_limit_handler(_: Request, exc: RateLimitExceeded):
    return JSONResponse(
        status_code=429,
        headers={"Retry-After": str(exc.retry_after)},
        content={
            "errors": [
                {
                    "field": None,
                    "code": "rate_limited",
                    "message": "Too many registration attempts. Try again later.",
                }
            ]
        },
    )


def error(field: str | None, code: str, message: str) -> dict[str, str | None]:
    return {"field": field, "code": code, "message": message}


def constant_time_equal(a: str, b: str) -> bool:
    left = hashlib.sha256(a.encode("utf-8")).digest()
    right = hashlib.sha256(b.encode("utf-8")).digest()
    return hmac.compare_digest(left, right)


def hmac_sha256(value: str) -> str:
    return hmac.new(APP_SECRET.encode(), value.encode(), hashlib.sha256).hexdigest()


def client_ip(request: Request) -> str:
    return request.client.host if request.client else "unknown"


async def consume_rate_limit(key: str, limit: int, window_seconds: int) -> None:
    now = time.monotonic()
    async with rate_limit_lock:
        bucket = rate_limit_store[key]
        while bucket and now - bucket[0] > window_seconds:
            bucket.popleft()

        if len(bucket) >= limit:
            retry_after = max(1, int(window_seconds - (now - bucket[0])))
            raise RateLimitExceeded(retry_after)

        bucket.append(now)


def unicode_security_errors(value: str, field: str) -> list[dict[str, str | None]]:
    issues = []

    if any(unicodedata.category(ch) in {"Cc", "Cs"} for ch in value):
        issues.append(error(field, "invalid_unicode_control", "Control and surrogate characters are not allowed."))

    if any(unicodedata.category(ch) == "Cf" for ch in value):
        issues.append(error(field, "invalid_unicode_invisible", "Invisible formatting characters are not allowed."))

    if any(is_noncharacter(ch) for ch in value):
        issues.append(error(field, "invalid_unicode_noncharacter", "Unicode noncharacters are not allowed."))

    return issues


def is_noncharacter(ch: str) -> bool:
    cp = ord(ch)
    return 0xFDD0 <= cp <= 0xFDEF or cp & 0xFFFE == 0xFFFE


def encode_idna(domain: str) -> str:
    try:
        import idna

        return idna.encode(domain, uts46=True, std3_rules=True).decode("ascii")
    except ImportError:
        return domain.encode("idna").decode("ascii")


def domain_has_dns_record(domain: str) -> bool | None:
    try:
        import dns.resolver
    except ImportError:
        return None

    resolver = dns.resolver.Resolver()
    resolver.timeout = 1.5
    resolver.lifetime = 2.5

    for record_type in ("MX", "A", "AAAA"):
        try:
            answers = resolver.resolve(domain, record_type)
            if answers:
                return True
        except dns.resolver.NXDOMAIN:
            return False
        except Exception:
            continue

    return False


def validate_email(value: Any) -> tuple[str | None, list[dict[str, str | None]]]:
    errors = []

    if not isinstance(value, str):
        return None, [error("email", "invalid_type", "Email must be a string.")]

    raw = unicodedata.normalize("NFKC", value).strip()
    errors.extend(unicode_security_errors(raw, "email"))

    if not raw:
        errors.append(error("email", "required", "Email is required."))

    if len(raw.encode("utf-8")) > 320:
        errors.append(error("email", "too_long", "Email is too long."))

    if any(ch.isspace() for ch in raw):
        errors.append(error("email", "whitespace", "Email must not contain whitespace."))

    if raw.count("@") != 1:
        errors.append(error("email", "invalid_format", "Email must contain exactly one @ sign."))
        return None, errors

    local, domain_raw = raw.rsplit("@", 1)
    domain_raw = domain_raw.strip().lower()

    if not local:
        errors.append(error("email", "missing_local_part", "Email local part is required."))

    if not domain_raw:
        errors.append(error("email", "missing_domain", "Email domain is required."))

    if len(local) > 64:
        errors.append(error("email", "local_part_too_long", "Email local part is too long."))

    if not local.isascii():
        errors.append(error("email", "smtp_utf8_unsupported", "Internationalized email local parts are not supported."))

    if local.startswith(".") or local.endswith(".") or ".." in local:
        errors.append(error("email", "invalid_local_dots", "Email local part has invalid dot placement."))

    if local and local.isascii() and not EMAIL_LOCAL_RE.fullmatch(local):
        errors.append(error("email", "invalid_local_chars", "Email local part contains invalid characters."))

    if domain_raw.endswith("."):
        errors.append(error("email", "invalid_domain", "Email domain must not end with a dot."))

    if domain_raw.startswith("[") or domain_raw.endswith("]"):
        errors.append(error("email", "ip_literal_domain", "IP-literal email domains are not allowed."))

    try:
        ipaddress.ip_address(domain_raw)
        errors.append(error("email", "ip_domain", "IP address email domains are not allowed."))
    except ValueError:
        pass

    try:
        domain = encode_idna(domain_raw)
    except Exception:
        errors.append(error("email", "invalid_idn_domain", "Email domain is not a valid IDN domain."))
        return None, errors

    labels = domain.split(".")

    if len(domain) > 253:
        errors.append(error("email", "domain_too_long", "Email domain is too long."))

    if len(labels) < 2:
        errors.append(error("email", "domain_missing_tld", "Email domain must include a public suffix."))

    for label in labels:
        if not label:
            errors.append(error("email", "empty_domain_label", "Email domain contains an empty label."))
            break
        if len(label) > 63:
            errors.append(error("email", "domain_label_too_long", "Email domain label is too long."))
            break
        if label.startswith("-") or label.endswith("-"):
            errors.append(error("email", "invalid_domain_hyphen", "Email domain labels must not start or end with hyphen."))
            break
        if "_" in label:
            errors.append(error("email", "invalid_domain_underscore", "Email domain labels must not contain underscores."))
            break

    tld = labels[-1]
    if len(tld) < 2 or tld.isdigit():
        errors.append(error("email", "invalid_tld", "Email top-level domain is invalid."))

    if domain in RESERVED_EMAIL_DOMAINS or any(domain.endswith("." + d) for d in RESERVED_EMAIL_DOMAINS):
        errors.append(error("email", "reserved_domain", "Reserved or local email domains are not allowed."))

    if domain in DISPOSABLE_EMAIL_DOMAINS or any(domain.endswith("." + d) for d in DISPOSABLE_EMAIL_DOMAINS):
        errors.append(error("email", "disposable_email", "Disposable email providers are not allowed."))

    if CHECK_EMAIL_DNS:
        dns_ok = domain_has_dns_record(domain)
        if dns_ok is False:
            errors.append(error("email", "unresolvable_domain", "Email domain has no usable DNS records."))

    canonical = f"{local.lower()}@{domain.lower()}"
    if len(canonical) > 254:
        errors.append(error("email", "too_long", "Email exceeds 254 characters."))

    return (None if errors else canonical), errors


def username_skeleton(username: str) -> str:
    return re.sub(r"[._-]+", "", username.translate(LEET_TABLE))


def validate_username(value: Any) -> tuple[tuple[str, str] | None, list[dict[str, str | None]]]:
    errors = []

    if not isinstance(value, str):
        return None, [error("username", "invalid_type", "Username must be a string.")]

    raw = unicodedata.normalize("NFKC", value).strip()
    username = raw.casefold()
    skeleton = username_skeleton(username)

    errors.extend(unicode_security_errors(raw, "username"))

    if not username:
        errors.append(error("username", "required", "Username is required."))

    if not username.isascii():
        errors.append(error("username", "non_ascii", "Username must use ASCII characters to prevent homoglyph spoofing."))

    if len(username) < 3:
        errors.append(error("username", "too_short", "Username must be at least 3 characters."))

    if len(username) > 30:
        errors.append(error("username", "too_long", "Username must be at most 30 characters."))

    if len(username.encode("utf-8")) > 30:
        errors.append(error("username", "too_long_bytes", "Username byte length is too long."))

    if username and not USERNAME_RE.fullmatch(username):
        errors.append(
            error(
                "username",
                "invalid_format",
                "Username may contain lowercase letters, numbers, dots, underscores, and hyphens; it must start and end with a letter or number.",
            )
        )

    if re.search(r"[._-]{2,}", username):
        errors.append(error("username", "repeated_separator", "Username must not contain repeated separators."))

    if skeleton in RESERVED_USERNAMES or any(skeleton.startswith(x) for x in {"admin", "support", "security", "moderator"}):
        errors.append(error("username", "reserved", "Username is reserved."))

    if any(term in skeleton for term in OFFENSIVE_TERMS):
        errors.append(error("username", "disallowed_content", "Username contains disallowed content."))

    return (None if errors else (username, skeleton)), errors


def validate_display_name(value: Any) -> tuple[str | None, list[dict[str, str | None]]]:
    errors = []

    if not isinstance(value, str):
        return None, [error("display_name", "invalid_type", "Display name must be a string.")]

    raw = unicodedata.normalize("NFKC", value)
    display_name = re.sub(r"\s+", " ", raw).strip()
    skeleton = username_skeleton(display_name.casefold())

    errors.extend(unicode_security_errors(display_name, "display_name"))

    if not display_name:
        errors.append(error("display_name", "required", "Display name is required."))

    if len(display_name) > 80:
        errors.append(error("display_name", "too_long", "Display name must be at most 80 characters."))

    if len(display_name.encode("utf-8")) > 160:
        errors.append(error("display_name", "too_long_bytes", "Display name byte length is too long."))

    if "<" in display_name or ">" in display_name:
        errors.append(error("display_name", "html_not_allowed", "Display name must not contain HTML markup."))

    if re.search(r"https?://|www\.", display_name, re.IGNORECASE):
        errors.append(error("display_name", "url_not_allowed", "Display name must not contain URLs."))

    if any(term in skeleton for term in OFFENSIVE_TERMS):
        errors.append(error("display_name", "disallowed_content", "Display name contains disallowed content."))

    return (None if errors else display_name), errors


def has_ascii_sequence(value: str, length: int = 4) -> bool:
    simplified = "".join(ch for ch in value.casefold() if ch.isascii() and ch.isalnum())
    for i in range(len(simplified) - length + 1):
        chunk = simplified[i : i + length]
        codes = [ord(ch) for ch in chunk]
        if all(codes[j] + 1 == codes[j + 1] for j in range(length - 1)):
            return True
        if all(codes[j] - 1 == codes[j + 1] for j in range(length - 1)):
            return True
    return False


def validate_password(value: Any, email: str | None, username: str | None, display_name: str | None) -> tuple[str | None, list[dict[str, str | None]]]:
    errors = []

    if not isinstance(value, str):
        return None, [error("password", "invalid_type", "Password must be a string.")]

    password = unicodedata.normalize("NFKC", value)
    lower = password.casefold()

    errors.extend(unicode_security_errors(password, "password"))

    if password != value:
        errors.append(error("password", "unicode_not_canonical", "Password contains non-canonical Unicode characters."))

    if len(password) < MIN_PASSWORD_CHARS:
        errors.append(error("password", "too_short", f"Password must be at least {MIN_PASSWORD_CHARS} characters."))

    if len(password) > MAX_PASSWORD_CHARS:
        errors.append(error("password", "too_long", f"Password must be at most {MAX_PASSWORD_CHARS} characters."))

    if len(password.encode("utf-8")) > 1024:
        errors.append(error("password", "too_long_bytes", "Password byte length is too large."))

    if password != password.strip():
        errors.append(error("password", "edge_whitespace", "Password must not start or end with whitespace."))

    categories = sum(
        [
            any(ch.islower() for ch in password),
            any(ch.isupper() for ch in password),
            any(ch.isdigit() for ch in password),
            any(not ch.isalnum() and not ch.isspace() for ch in password),
        ]
    )
    if categories < 3:
        errors.append(error("password", "insufficient_complexity", "Password must include at least 3 of: lowercase, uppercase, digit, symbol."))

    if lower in COMMON_PASSWORDS or lower.replace(" ", "") in COMMON_PASSWORDS:
        errors.append(error("password", "common_password", "Password is too common."))

    if len(set(lower)) < 5:
        errors.append(error("password", "low_variation", "Password must contain more unique characters."))

    if re.search(r"(.)\1{3,}", password):
        errors.append(error("password", "repeated_characters", "Password contains too many repeated characters."))

    if re.fullmatch(r"\d+", password):
        errors.append(error("password", "all_digits", "Password must not be entirely numeric."))

    if re.fullmatch(r"[A-Za-z]+", password):
        errors.append(error("password", "all_letters", "Password must not be entirely letters."))

    if has_ascii_sequence(password):
        errors.append(error("password", "sequential_characters", "Password contains sequential characters."))

    if any(seq in lower for seq in KEYBOARD_SEQUENCES):
        errors.append(error("password", "keyboard_pattern", "Password contains a keyboard or common pattern."))

    identifiers = []
    if email and "@" in email:
        local, domain = email.split("@", 1)
        identifiers.extend([("email", local), ("email_domain", domain.split(".")[0])])
    if username:
        identifiers.append(("username", username))
    if display_name:
        identifiers.append(("display_name", re.sub(r"\s+", "", display_name.casefold())))

    for source, identifier in identifiers:
        identifier = identifier.casefold()
        if len(identifier) < 3:
            continue
        if constant_time_equal(lower, identifier):
            errors.append(error("password", "matches_identifier", f"Password must not match {source}."))
        elif identifier in lower:
            errors.append(error("password", "contains_identifier", f"Password must not contain {source}."))
        elif len(identifier) >= 4 and SequenceMatcher(None, lower, identifier).ratio() >= 0.72:
            errors.append(error("password", "similar_to_identifier", f"Password is too similar to {source}."))

    return (None if errors else password), errors


def pwned_password_count(password: str) -> int | None:
    if not CHECK_BREACHED_PASSWORDS:
        return None

    try:
        try:
            digest = hashlib.sha1(password.encode("utf-8"), usedforsecurity=False).hexdigest().upper()
        except TypeError:
            digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()

        prefix, suffix = digest[:5], digest[5:]
        request = urllib.request.Request(
            f"https://api.pwnedpasswords.com/range/{prefix}",
            headers={"User-Agent": "registration-validator", "Add-Padding": "true"},
        )

        with urllib.request.urlopen(request, timeout=2.5) as response:
            for line in response.read().decode("utf-8", "replace").splitlines():
                candidate, _, count = line.partition(":")
                if hmac.compare_digest(candidate.upper(), suffix):
                    return int(count)
    except Exception:
        return None

    return 0


async def read_json_body(request: Request) -> tuple[Any | None, JSONResponse | None]:
    content_type = request.headers.get("content-type", "").split(";")[0].lower()
    if content_type != "application/json":
        return None, JSONResponse(
            status_code=415,
            content={"errors": [error(None, "unsupported_media_type", "Content-Type must be application/json.")]},
        )

    content_length = request.headers.get("content-length")
    if content_length:
        try:
            if int(content_length) > MAX_BODY_BYTES:
                return None, JSONResponse(
                    status_code=413,
                    content={"errors": [error(None, "payload_too_large", "Request body is too large.")]},
                )
        except ValueError:
            return None, JSONResponse(status_code=400, content={"errors": [error(None, "bad_content_length", "Invalid Content-Length.")]})

    body = await request.body()
    if len(body) > MAX_BODY_BYTES:
        return None, JSONResponse(status_code=413, content={"errors": [error(None, "payload_too_large", "Request body is too large.")]})

    try:
        return json.loads(body.decode("utf-8")), None
    except Exception:
        return None, JSONResponse(status_code=400, content={"errors": [error(None, "invalid_json", "Request body must be valid UTF-8 JSON.")]})


def validate_payload(payload: Any) -> tuple[CleanRegistration | None, list[dict[str, str | None]]]:
    errors = []

    if not isinstance(payload, dict):
        return None, [error(None, "invalid_body", "Request body must be a JSON object.")]

    allowed = {"email", "username", "password", "display_name"}
    required = {"email", "username", "password", "display_name"}

    for key in payload:
        if key not in allowed:
            errors.append(error(key, "unknown_field", "Unknown field is not allowed."))

    for key in required:
        if key not in payload:
            errors.append(error(key, "missing_field", "Field is required."))

    email, email_errors = validate_email(payload.get("email"))
    username_result, username_errors = validate_username(payload.get("username"))
    display_name, display_errors = validate_display_name(payload.get("display_name"))

    username = username_result[0] if username_result else None
    username_skel = username_result[1] if username_result else None

    password, password_errors = validate_password(payload.get("password"), email, username, display_name)

    errors.extend(email_errors)
    errors.extend(username_errors)
    errors.extend(display_errors)
    errors.extend(password_errors)

    if errors:
        return None, errors

    return CleanRegistration(
        email=email,
        username=username,
        username_skeleton=username_skel,
        password=password,
        display_name=display_name,
    ), []


def check_browser_request_safety(request: Request) -> JSONResponse | None:
    origin = request.headers.get("origin")

    if origin and ALLOWED_ORIGINS and origin not in ALLOWED_ORIGINS:
        return JSONResponse(
            status_code=403,
            content={"errors": [error(None, "bad_origin", "Request origin is not allowed.")]},
        )

    if request.headers.get("cookie"):
        csrf_cookie = request.cookies.get("csrf_token", "")
        csrf_header = request.headers.get("x-csrf-token", "")
        if not csrf_cookie or not csrf_header or not hmac.compare_digest(csrf_cookie, csrf_header):
            return JSONResponse(
                status_code=403,
                content={"errors": [error(None, "csrf_failed", "CSRF validation failed.")]},
            )

    return None


def insert_user(clean: CleanRegistration, password_hash: str) -> None:
    now = datetime.now(timezone.utc)

    # SQLAlchemy emits parameterized SQL with bound parameters here.
    stmt = insert(users).values(
        email=clean.email,
        email_hash=hmac_sha256(clean.email),
        username=clean.username,
        username_skeleton=clean.username_skeleton,
        display_name=clean.display_name,
        password_hash=password_hash,
        email_verified=False,
        created_at=now,
        updated_at=now,
    )

    with engine.begin() as conn:
        conn.execute(stmt)


def accepted_response() -> JSONResponse:
    # Same response for success and duplicates to prevent account enumeration.
    return JSONResponse(
        status_code=202,
        content={
            "status": "accepted",
            "message": "If the registration can be completed, the account will be created.",
        },
    )


@app.post("/api/register")
async def register(request: Request):
    await consume_rate_limit(f"register:ip:{client_ip(request)}", limit=10, window_seconds=60)

    csrf_error = check_browser_request_safety(request)
    if csrf_error:
        return csrf_error

    payload, body_error = await read_json_body(request)
    if body_error:
        return body_error

    clean, validation_errors = validate_payload(payload)

    raw_password = payload.get("password") if isinstance(payload, dict) else None
    if isinstance(raw_password, str) and len(raw_password) <= MAX_PASSWORD_CHARS:
        normalized_password = unicodedata.normalize("NFKC", raw_password)
        breach_count = await asyncio.to_thread(pwned_password_count, normalized_password)
        if breach_count and breach_count > 0:
            validation_errors.append(
                error("password", "breached_password", "Password appears in known breach data and cannot be used.")
            )

    if validation_errors:
        return JSONResponse(status_code=422, content={"errors": validation_errors})

    await consume_rate_limit(f"register:email:{hmac_sha256(clean.email)}", limit=5, window_seconds=3600)
    await consume_rate_limit(f"register:username:{hmac_sha256(clean.username)}", limit=5, window_seconds=3600)

    password_hash = await asyncio.to_thread(password_hasher.hash, clean.password + PASSWORD_PEPPER)

    try:
        await asyncio.to_thread(insert_user, clean, password_hash)
    except IntegrityError:
        # Duplicate email/username/skeleton is intentionally indistinguishable from success.
        pass

    return accepted_response()
